console.log("base loaded!");const menu=document.querySelector(".menu"),menuSection=menu.querySelector(".menu-section"),menuArrow=menu.querySelector(".menu-mobile-arrow"),menuClosed=menu.querySelector(".menu-mobile-close"),menuTrigger=document.querySelector(".menu-mobile-trigger"),menuOverlay=document.querySelector(".overlay");let subMenu;function toggleMenu(){menu.classList.toggle("active"),menuOverlay.classList.toggle("active")}function showSubMenu(hasChildren){(subMenu=hasChildren.querySelector(".menu-subs")).classList.add("active"),subMenu.style.animation="slideLeft 0.5s ease forwards";hasChildren=hasChildren.querySelector("i").parentNode.childNodes[0].textContent;menu.querySelector(".menu-mobile-title").innerHTML=hasChildren,menu.querySelector(".menu-mobile-header").classList.add("active")}function hideSubMenu(){subMenu.style.animation="slideRight 0.5s ease forwards",setTimeout(()=>{subMenu.classList.remove("active")},300),menu.querySelector(".menu-mobile-title").innerHTML="",menu.querySelector(".menu-mobile-header").classList.remove("active")}menuSection.addEventListener("click",e=>{menu.classList.contains("active")&&e.target.closest(".menu-item-has-children")&&showSubMenu(e.target.closest(".menu-item-has-children"))}),menuArrow.addEventListener("click",()=>{hideSubMenu()}),menuTrigger.addEventListener("click",()=>{toggleMenu()}),menuClosed.addEventListener("click",()=>{toggleMenu()}),menuOverlay.addEventListener("click",()=>{toggleMenu()}),window.onresize=function(){991<this.innerWidth&&menu.classList.contains("active")&&toggleMenu()};const swiper=new Swiper(".swiper",{direction:"horizontal",loop:!0,pagination:{el:".swiper-pagination"},navigation:{nextEl:".swiper-button-next",prevEl:".swiper-button-prev"},breakpoints:{768:{navigation:!1}}});